import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";
import IncomeExpandedContent, { INCOME_EXPANDED_FAQS } from "@/components/IncomeExpandedContent";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

function fmt(n: number) {
  return formatCurrencyValue(n, { maximumFractionDigits: 2 });
}
function fmtVisitors(n: number) {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M visitors`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(0)}K visitors`;
  return `${n} visitors`;
}


const FAQS = [
  { q: "What is a realistic CTR for display ads?", a: "Average display ad CTR is 0.1-0.3%. Content-rich websites in specialized niches can see 0.5-1%. Social and native ads typically outperform banner ads. Optimizing ad placement (above the fold, in-content) significantly affects CTR." },
  { q: "What CPC can I expect from Google AdSense?", a: "Google AdSense CPC averages $0.20-$1.50 for general content sites. Finance, insurance, and legal niches can see $3-$15+ per click. CPC varies by audience geography - US/UK/AU traffic earns significantly more than other regions." },
  { q: "How many visitors do I need to earn $1,000/month from ads?", a: "At a $0.50 CPC and 0.2% CTR: clicks = visitors  x  0.002, revenue = clicks  x  $0.50. To earn $1,000: 1,000  x  $0.50 = 2,000 clicks needed,  x  0.002 = 1,000,000 visitors/month required. Higher CPCs dramatically reduce this threshold." },
  { q: "How can I increase my ad revenue without more traffic?", a: "Optimize ad placement, test ad formats (native vs. display vs. in-content), improve audience targeting, focus on higher-CPM content niches, and reduce page load time to lower bounce rate." },
  { q: "What is RPM in website advertising?", a: "RPM (Revenue Per Mille) is the estimated revenue per 1,000 page views. RPM = (Estimated Earnings  x  Page Views)  x  1,000. Most general content sites earn $1-$5 RPM; finance and legal niches can reach $20-$50 RPM." },
  { q: "How does ad revenue differ by traffic source?", a: "Organic search traffic from the US, UK, Canada, and Australia earns the highest CPC. Social media traffic often has lower intent and earns less. Email newsletter traffic can outperform both if the audience is engaged and niche-focused." },
  { q: "Should I use Google AdSense or direct ad sales?", a: "AdSense is easiest to set up and works well for sites under 100K monthly visitors. Direct ad sales yield higher revenue per impression at larger scale. Many publishers use AdSense as a floor while pursuing direct deals for premium placements." },
];

const EXPANDED_FAQS = INCOME_EXPANDED_FAQS.websiteAdRevenue;

